deploy.startCommand:
php artisan migrate --force && printf '{
	auto_https off
	admin off
	frankenphp
	servers {
		trusted_proxies static private_ranges
	}
}

:%s {
	root * /app/public
	encode zstd br gzip
	php_server
}
' "$PORT" > /etc/caddy/Caddyfile && frankenphp run --config /etc/caddy/Caddyfile
